  `context_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Dữ liệu ngữ cảnh thêm (stack trace, query, etc.)' CHECK (json_valid(`context_data`)),
  `fingerprint` varchar(32) DEFAULT NULL COMMENT 'MD5 hash để nhóm lỗi giống nhau',
  `occurrence_count` int(10) unsigned NOT NULL DEFAULT 1 COMMENT 'Số lần lỗi xảy ra',
  `ai_analyzed` tinyint(1) NOT NULL DEFAULT 0,
  `ai_analysis` text DEFAULT NULL COMMENT 'Phân tích của Gemini AI',
  `messenger_sent` tinyint(1) NOT NULL DEFAULT 0,
  `messenger_sent_at` datetime DEFAULT NULL,
  `status` enum('open','in_progress','resolved','ignored') NOT NULL DEFAULT 'open',
  `resolved_by` int(10) unsigned DEFAULT NULL,
  `resolved_at` datetime DEFAULT NULL,
  `notes` text DEFAULT NULL COMMENT 'Ghi chú của admin',
  `last_seen_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_severity` (`severity`),
  KEY `idx_error_type` (`error_type`),
  KEY `idx_status` (`status`),
  KEY `idx_fingerprint` (`fingerprint`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_ai_analyzed` (`ai_analyzed`)
) ENGINE=InnoDB AUTO_INCREMENT=345 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Bảng lưu trữ lỗi AI Bug Tracker';

