-- Table structure for table `membership_tiers`
DROP TABLE IF EXISTS `membership_tiers`;
CREATE TABLE `membership_tiers` (
  `tier_id` int(11) NOT NULL AUTO_INCREMENT,
  `tier_name` varchar(50) NOT NULL,
  `tier_name_en` varchar(50) DEFAULT NULL,
  `tier_level` int(11) NOT NULL,
  `min_points` int(11) NOT NULL DEFAULT 0,
  `discount_percentage` decimal(5,2) DEFAULT 0.00,
  `benefits` text DEFAULT NULL,
  `benefits_en` text DEFAULT NULL,
  `color_code` varchar(7) DEFAULT '#000000',
  `icon` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`tier_id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Dumping data for table `membership_tiers`
INSERT INTO `membership_tiers` VALUES
('1','Thành Viên','Member','0','0','0.00','Tích lũy VNDiểm thưởng cho mỗi lần VNDặt phòng. 10.000đ = 1 VNDiểm. Điểm có hiệu lực 365 ngày.','Earn reward points for every booking. 10,000 VND = 1 point. Points valid for 365 days.','#94A3B8','fa-user','2026-03-03 16:26:38'),
('2','Bạc','Silver','1','5000','5.00','Giảm 5% tổng hóa VNDơn lưu trú. Tích VNDiểm x1.5. Check-in ưu tiên. Quà tặng chào mừng khi nhận phòng.','5% discount on stay. 1.5x point earning. Priority check-in. Welcome gift.','#94A3B8','fa-medal','2026-03-03 16:26:38'),
('3','Vàng','Gold','2','10000','10.00','Giảm 10% tổng hóa VNDơn. Tích VNDiểm x2. Late check-out VNDến 13:00 miễn phí. Đặt phòng ưu tiên. Complimentary breakfast 1 ngày.','10% discount. 2x points. Free late checkout to 13:00. Priority booking. 1 complimentary breakfast.','#F59E0B','fa-star','2026-03-03 16:26:38'),
('4','Bạch Kim','Platinum','3','20000','15.00','Giảm 15% tổng hóa VNDơn. Tích VNDiểm x3. Late check-out VNDến 14:00. Early check-in từ 10:00. Nâng cấp phòng miễn phí (tùy availability). Bữa sáng miễn phí mỗi ngày. Ưu VNDãi Spa 20%. Đón tiếp riêng VIP.','15% discount. 3x points. Late checkout 14:00. Early check-in 10:00. Free room upgrade. Daily breakfast. 20% spa discount. VIP welcome.','#E2E8F0','fa-crown','2026-03-03 16:26:38');

-- Table structure for table `notifications`
DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (
  `notification_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `type` varchar(50) NOT NULL,
  `title` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `link` varchar(255) DEFAULT NULL,
  `icon` varchar(50) DEFAULT NULL,
  `is_read` tinyint(1) DEFAULT 0,
  `read_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`notification_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for table `page_content`
DROP TABLE IF EXISTS `page_content`;
CREATE TABLE `page_content` (
  `content_id` int(11) NOT NULL AUTO_INCREMENT,
  `page_name` varchar(100) NOT NULL,
  `section_name` varchar(100) NOT NULL,
  `content_key` varchar(100) NOT NULL,
  `content_value` text NOT NULL,
  `content_type` enum('text','html','image','json') DEFAULT 'text',
  `language` varchar(5) DEFAULT 'vi',
  `updated_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`content_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for table `password_resets`
DROP TABLE IF EXISTS `password_resets`;
CREATE TABLE `password_resets` (
  `reset_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `token` varchar(255) NOT NULL,
  `expires_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `used` tinyint(1) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`reset_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for table `payments`
DROP TABLE IF EXISTS `payments`;
CREATE TABLE `payments` (
  `payment_id` int(11) NOT NULL AUTO_INCREMENT,
  `booking_id` int(11) NOT NULL,
  `payment_method` enum('vnpay','cash','bank_transfer','credit_card') NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `currency` varchar(3) DEFAULT 'VND',
  `transaction_id` varchar(255) DEFAULT NULL,
  `vnpay_response` text DEFAULT NULL,
  `status` enum('pending','completed','failed','refunded') DEFAULT 'pending',
  `paid_at` timestamp NULL DEFAULT NULL,
  `refunded_at` timestamp NULL DEFAULT NULL,
  `refund_amount` decimal(10,2) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`payment_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for table `points_transactions`
DROP TABLE IF EXISTS `points_transactions`;
CREATE TABLE `points_transactions` (
  `transaction_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `points` int(11) NOT NULL,
  `transaction_type` enum('earn','redeem','expire','adjust') NOT NULL,
  `reference_type` varchar(50) DEFAULT NULL,
  `reference_id` int(11) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`transaction_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for table `pricing_policies`
DROP TABLE IF EXISTS `pricing_policies`;
